  // Represents a math operation with two sides (e.g. x+2 or y-4). Left and right can be either variables or numbers
  static class BinOpExpr extends Expr {
      char op;
      Expr left, right;

      BinOpExpr(char o, Expr l, Expr r) {
          op = o; left = l; right = r;
      }

      // Calculate left and right side respectively and combine them through provided math ops
      long evaluate(long v1, long v2, String i1, String i2) {
          long leftValue = left.evaluate(v1, v2, i1, i2);
          long rightValue = right.evaluate(v1, v2, i1, i2);
          if (op == '+') {
              return leftValue + rightValue;
          }
          if (op == '-') {
              return leftValue - rightValue;
          }
          if (op == '*'){
              return leftValue * rightValue;
          }
          throw new RuntimeException("Unknown operator: " + op);
      }

      // Rule S1. Check if this operator or left/right is a multiplication '*'
      boolean hasMultiply() {
          return op == '*' || left.hasMultiply() || right.hasMultiply();
      }
      // Rule S2. Check if there is any subtraction
      boolean hasAnySub() {
          return op == '-' || left.hasAnySub() || right.hasAnySub();
      }
      // Rule S2. Check if there is unallowed subtraction
      boolean hasInvalidSub() {
          // If the operator is a minus, the right side must be a number. Cannot be variable
          if (op == '-' && !(right instanceof NumExpr)) {
              return true;
          }
          // Recursively check if there is any invalid subtraction on both sides
          return left.hasInvalidSub() || right.hasInvalidSub();
      }
  }

