  // Audits a step to ensure it complies with rules S1, S2, and S3
  boolean auditSimpleRules(StepData step) {
      // Group expressions for easier S1,S2,S3 checking
      Expr[] allExprs = {step.e1, step.e2, step.e3, step.e4};
      Expr[] trueBranchExprs = {step.e1, step.e2};
      Expr[] falseBranchExprs = {step.e3, step.e4};

      // S1: Positive linear check on all expressions. Multiplication and invalid subtraction are checked
      for (Expr e : allExprs) {
          if (e != null && !e.isPositiveLinear()) {
              return false;
          }
      }

      // S2: No subtraction allowed in the True Branch
      for (Expr e : trueBranchExprs) {
          if (e != null && e.hasAnySub()) {
              return false;
          }
      }

      // S3: If condition is false, result coordinates cannot be negative
      // Since we are not running the live simulation yet, we create a fake worst case scenario
      long minConditionVariable = Math.max(0, step.conditionThreshold);
      long minOtherVariable = 0;

      long testId1 = step.conditionVariable.equals(step.id1) ? minConditionVariable : minOtherVariable;
      long testId2 = step.conditionVariable.equals(step.id2) ? minConditionVariable : minOtherVariable;

      for (Expr e : falseBranchExprs) {
          if (e != null && e.evaluate(testId1, testId2, step.id1, step.id2) < 0) {
              return false;
          }
      }
      return true; // Pass all audits!!
      }

  // Main interpreter that executes the TPTP program and loop with loop detection
  void executeInterpreter() {
      String currentStepName = runTarget;
      long currentX = runNum1;
      long currentY = runNum2;

      // Detect any loops if state (step, x, y) is repeated
      Set<String> visited = new HashSet<>();

      while (true) {
          // 1. Halt check - Does the target step actually exist?
          // Print coordinates and end if no
          if (!stepMemory.containsKey(currentStepName)) {
              System.out.println(currentStepName + " " + currentX + " " + currentY);
              return;
          }

          // 2. Loop detection if a step is repeated
          String state = currentStepName + ',' + currentX + ',' + currentY;
          if (visited.contains(state)) {
              System.out.println("Loop");
              return;
          }
          visited.add(state);

          // 3. Execute current step and evaluate expressions before updating coordinates
          StepData step = stepMemory.get(currentStepName);
          long coordinateValue = step.conditionVariable.equals(step.id1) ? currentX : currentY;
          boolean isConditionTrue = coordinateValue < step.conditionThreshold;

          long newX, newY;
          if (isConditionTrue) {
              newX = step.e1 != null ? step.e1.evaluate(currentX, currentY, step.id1, step.id2) : currentX;
              newY = step.e2 != null ? step.e2.evaluate(currentX, currentY, step.id1, step.id2) : currentY;
              currentStepName = step.NSTEP;
          } else {
              newX = step.e3 != null ? step.e3.evaluate(currentX, currentY, step.id1, step.id2) : currentX;
              newY = step.e4 != null ? step.e4.evaluate(currentX, currentY, step.id1, step.id2) : currentY;
              currentStepName = step.ESTEP;
          }
          currentX = newX;
          currentY = newY;
      }
  }

